import React, { useContext , useState } from "react";
import { FormContext } from "../Contexts/FormContext";
import { EventCaller, ServerEventCaller } from "../BusinessLogics/EventHandler";

export const DateBox = ({ eid, fieldname, cap, col, mn, ev, val, mxLen , rid}) => {

  const { register, formState: { errors } } = useContext(FormContext);

  const { setValue, getValues, eDefHldr, stageGridRefs, watch, trigger , stageElements , cntrData } = useContext(FormContext);

  
  const FormContextdata =  {
    getValues: getValues,
    stageGridRefs: stageGridRefs,
    stageElements: stageElements,
    cntrData: cntrData,
  };

  const [formData, setFormData] = useState({});


  let clientevent ={}
  if (ev) {
    clientevent = JSON.parse(ev.change);
  }

    /* store previous value to avoid event fire when tabout */
    const handleChange = (e) => {
      const { name, value } = e.target;
      setFormData(prevState => ({ ...prevState, [name]: value }));
    };

    
  return (
    <div className={`${col} mb-3`}>
      <label
        htmlFor={fieldname}
        className={`${mn ? "required" : ""} form-label`}
      >
        {cap}
      </label>
      <input
        name={fieldname}
        type="date"
        className="form-control"
        {...register(fieldname, {
          required: mn,
          maxLength: { mxLen, message: " is required" },
          value: val,
          onBlur: (e) => {
            if (clientevent.fn) {
              EventCaller(
                clientevent.fn,
                fieldname,
                clientevent.outel,
                getValues,
                setValue
              )
            }
            if (eDefHldr.stg.sev[fieldname]) {

              const currentValues = watch(fieldname);

              const previousValue = formData[fieldname];

              if (previousValue !== currentValues) {

                ServerEventCaller(
                  eDefHldr,
                  getValues(),
                  eDefHldr.stg.sev[fieldname].ev.change,
                  stageGridRefs,
                  setValue,
                  FormContextdata
                )
                handleChange(e)
              }
            }
          }
        })}
      />

            {/* use role="alert" to announce the error message */}

            {errors[fieldname] && errors[fieldname].type == "required" && (

<span role="alert" style={{color: "red" ,
fontSize: "12px"}}>This field is required</span>
)}
{errors[fieldname] && errors[fieldname].type == "maxLength" && (
<span role="alert"style={{color: "red" ,
fontSize: "12px"}}>Max length exceeded</span>
)}


    </div>
  );
};

export default DateBox;
